mapper.select:
SELECT * FROM (
    SELECT t.*, ROWNUM rn FROM (
        SELECT * FROM POWER_RECORD

            AND RECORD_DATE >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
            AND RECORD_DATE <= TO_DATE(#{endDate}, 'YYYY-MM-DD')

        ORDER BY RECORD_DATE DESC
    ) t WHERE ROWNUM <= #{offset} + #{limit}
) WHERE rn > #{offset}
